#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n;    cin >> n;        vll a(n);    for(int i=0; i<n; i++) cin >> a[i];    bool possible = false;        for(int i=1; i<n-1; i++) {        ll j=INT_MIN, k=INT_MIN;        for(int m=0;m<i;m++){            if(a[m]<a[i]){                j=m;                break;            }                     }        for(int m=i+1;m<n;m++){            if(a[i]>a[m]){                k=m;                break;            }        }        if(j!=INT_MIN && k!=INT_MIN){            cout<<"YES\n";            cout<<j+1<<" "<<i+1<<" "<<k+1<<"\n";            possible = true;            break;        }    }    if(!possible) cout<<"NO\n";          } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}